def validate(args, output):
    s = args[0]
    # Check output is a subsequence of s
    it = iter(s)
    for c in output:
        for ch in it:
            if ch == c:
                break
        else:
            return False
    # Check output is a valid parentheses string (all parens balanced)
    depth = 0
    for c in output:
        if c == '(':
            depth += 1
        elif c == ')':
            depth -= 1
            if depth < 0:
                return False
    if depth != 0:
        return False
    # Check minimality: count removed parens
    removed = len(s) - len(output)
    # Compute minimum removals needed from s
    def min_remove(t):
        stack = []
        invalid = set()
        for i, c in enumerate(t):
            if c == '(':
                stack.append(i)
            elif c == ')':
                if stack:
                    stack.pop()
                else:
                    invalid.add(i)
        invalid.update(stack)
        return len(invalid)
    return removed == min_remove(s)

