function validate(args, output) {
    const s = args[0];
    // Check output is a subsequence of s
    let si = 0;
    for (const c of output) {
        while (si < s.length && s[si] !== c) si++;
        if (si >= s.length) return false;
        si++;
    }
    // Check parentheses validity
    let depth = 0;
    for (const c of output) {
        if (c === '(') depth++;
        else if (c === ')') { depth--; if (depth < 0) return false; }
    }
    if (depth !== 0) return false;
    // Check minimality
    const removed = s.length - output.length;
    function minRemove(t) {
        const stack = [];
        const invalid = new Set();
        for (let i = 0; i < t.length; i++) {
            if (t[i] === '(') stack.push(i);
            else if (t[i] === ')') {
                if (stack.length > 0) stack.pop();
                else invalid.add(i);
            }
        }
        for (const i of stack) invalid.add(i);
        return invalid.size;
    }
    return removed === minRemove(s);
}

