    const arr = s.split('');
    const stack = [];
    for (let i = 0; i < arr.length; i++) {
        if (arr[i] === '(') stack.push(i);
        else if (arr[i] === ')') {
            if (stack.length > 0) stack.pop();
            else arr[i] = '';
        }
    }
